function Counter() {
  const [count, setCount] = useState(0);
  const [person, setPerson] = useState({ name: '', age: 0 });
  const memoizedState = useMemo(() => ({ count, person }), [count, person]);
  useEffect(() => {
    // Fix this code to prevent unnecessary re-renders
  }, [memoizedState]);
  return (
    <div>
      <p>Count: {count}</p>
      <p>Name: {person.name}</p>
      <p>Age: {person.age}</p>
    </div>
  );
}

